const body = $('Webhook').item.json.body;

// Para memoria persistente, el frontend DEBE enviar un sessionId constante
// Si no viene, usamos userId, o generamos uno temporal (se perderá la memoria al refrescar)
const sessionId = body.sessionId || body.userId || ('anon_' + Date.now().toString());

return {
  json: {
    sessionId: sessionId,
    message: body.message,
    queryContext: {
       timestamp: new Date().toISOString(),
       source: 'frontend-bot'
    }
  }
}

